+ 		    stupid = 1;
++		} else if ( *opt == 'v' ) {
++		    verbose++;
++		} else if ( *opt == 'b' && argp[1] ) {
++		    load_boot_image(*++argp);
+ 		} else if (*opt == 'r') {
+ 		    raid_mode = 1;
+ 		} else if (*opt == 'f') {
+@@ -220,11 +273,10 @@
+     fprintf(mtc,
+ 	    /* "MTOOLS_NO_VFAT=1\n" */
+ 	    "MTOOLS_SKIP_CHECK=1\n"	/* Needed for some flash memories */
+-	    "drive s:\n"
+-	    "  file=\"/proc/%lu/fd/%d\"\n"
++	    "drive s: file=\"%s\"\n"
+ 	    "  offset=%llu\n",
+ 	    (unsigned long)mypid,
+-	    dev_fd, (unsigned long long)filesystem_offset);
++	    device, (unsigned long long)filesystem_offset);
+     fclose(mtc);
+ 
+     /*
+@@ -236,8 +288,10 @@
+     }
+ 
